import http.server
import socketserver
from prometheus_client import start_http_server, Counter

# Define a counter metric to track HTTP requests
request_counter = {}

class RequestHandler(http.server.SimpleHTTPRequestHandler):
    def do_GET(self):
        # Extract user_id and session_id from headers (example implementation)
        user_id = self.headers.get('X-User-ID', 'unknown')
        session_id = self.headers.get('X-Session-ID', 'unknown')

        # Create a unique label for each user-path combination
        label = f"user:{user_id}_path:{self.path}"

        # Check if the metric already exists, if not, create it
        if label not in request_counter:
            request_counter[label] = Counter(f"http_requests_total_{label}", 'Total HTTP requests', ['method', 'path'])

        # Increment the counter for the specific user-path combination and method
        request_counter[label].labels(method='GET', path=self.path).inc()

        # Continue with the original handler logic to serve the request
        super().do_GET()

# Start Prometheus HTTP server on port 8000 (or any other desired port)
start_http_server(8000)

# Set up a simple HTTP server on port 8080
with socketserver.TCPServer(("", 8080), RequestHandler) as httpd:
    print("Serving at port 8080")
    httpd.serve_forever()